'use client';

/**
 * Calculadora de ROI
 */

import { useState, useMemo } from 'react';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Badge } from '@/components/ui/badge';
import { Separator } from '@/components/ui/separator';
import { Slider } from '@/components/ui/slider';
import {
    Target,
    DollarSign,
    TrendingUp,
    ArrowLeft,
    ThumbsUp,
    ThumbsDown,
    Users,
    ShoppingCart
} from 'lucide-react';
import Link from 'next/link';

interface ROIInputs {
    totalInvestment: number;
    leadsGenerated: number;
    conversionRateMin: number;
    conversionRateMax: number;
    averageTicket: number;
}

export default function ROICalculatorPage() {
    const [inputs, setInputs] = useState<ROIInputs>({
        totalInvestment: 4500,
        leadsGenerated: 70,
        conversionRateMin: 20,
        conversionRateMax: 40,
        averageTicket: 300
    });

    const updateInput = (field: keyof ROIInputs, value: number) => {
        setInputs(prev => ({ ...prev, [field]: value }));
    };

    const scenarios = useMemo(() => {
        const { totalInvestment, leadsGenerated, conversionRateMin, conversionRateMax, averageTicket } = inputs;

        const pessimistic = {
            name: 'Pessimista',
            conversionRate: conversionRateMin,
            sales: Math.round(leadsGenerated * (conversionRateMin / 100)),
            revenue: leadsGenerated * (conversionRateMin / 100) * averageTicket
        };

        const median = {
            name: 'Mediano',
            conversionRate: (conversionRateMin + conversionRateMax) / 2,
            sales: Math.round(leadsGenerated * ((conversionRateMin + conversionRateMax) / 200)),
            revenue: leadsGenerated * ((conversionRateMin + conversionRateMax) / 200) * averageTicket
        };

        const optimistic = {
            name: 'Otimista',
            conversionRate: conversionRateMax,
            sales: Math.round(leadsGenerated * (conversionRateMax / 100)),
            revenue: leadsGenerated * (conversionRateMax / 100) * averageTicket
        };

        return [pessimistic, median, optimistic].map(scenario => ({
            ...scenario,
            roas: scenario.revenue / totalInvestment,
            roi: ((scenario.revenue - totalInvestment) / totalInvestment) * 100,
            profit: scenario.revenue - totalInvestment
        }));
    }, [inputs]);

    const formatCurrency = (value: number) => {
        return value.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });
    };

    const getROIColor = (roi: number) => {
        if (roi < 0) return 'text-red-500';
        if (roi < 100) return 'text-yellow-500';
        return 'text-green-500';
    };

    return (
        <div className="min-h-screen space-y-8 bg-background pb-20">
            {/* Header */}
            <div className="flex items-center gap-4">
                <Link href="/calculators">
                    <Button variant="ghost" size="icon">
                        <ArrowLeft className="h-5 w-5" />
                    </Button>
                </Link>
                <div className="bg-gradient-to-br from-green-600 via-green-600 to-green-700 rounded-xl p-6 text-white shadow-lg flex-1">
                    <div className="flex items-center gap-4">
                        <Target className="w-10 h-10" />
                        <div>
                            <h1 className="text-2xl font-bold">Calculadora de ROI</h1>
                            <p className="text-white/90">Retorno Sobre o Investimento</p>
                        </div>
                    </div>
                </div>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                {/* Inputs */}
                <div className="space-y-6">
                    {/* Investimento */}
                    <Card>
                        <CardHeader>
                            <CardTitle className="flex items-center gap-2">
                                <DollarSign className="w-5 h-5 text-green-600" />
                                Investimento
                            </CardTitle>
                            <CardDescription>Custos totais da campanha</CardDescription>
                        </CardHeader>
                        <CardContent className="space-y-4">
                            <div className="space-y-2">
                                <Label>Custo Total do Investimento</Label>
                                <div className="relative">
                                    <span className="absolute left-3 top-1/2 transform -translate-y-1/2 text-muted-foreground">R$</span>
                                    <Input
                                        type="number"
                                        value={inputs.totalInvestment}
                                        onChange={(e) => updateInput('totalInvestment', Number(e.target.value))}
                                        className="pl-10"
                                    />
                                </div>
                            </div>
                        </CardContent>
                    </Card>

                    {/* Métricas de Retorno */}
                    <Card>
                        <CardHeader>
                            <CardTitle className="flex items-center gap-2">
                                <TrendingUp className="w-5 h-5 text-green-600" />
                                Métricas de Retorno
                            </CardTitle>
                            <CardDescription>Previsão de resultados</CardDescription>
                        </CardHeader>
                        <CardContent className="space-y-6">
                            <div className="space-y-2">
                                <Label className="flex items-center gap-2">
                                    <Users className="w-4 h-4" />
                                    Leads Gerados
                                </Label>
                                <Input
                                    type="number"
                                    value={inputs.leadsGenerated}
                                    onChange={(e) => updateInput('leadsGenerated', Number(e.target.value))}
                                />
                            </div>

                            <Separator />

                            <div className="space-y-4">
                                <Label>Taxa de Conversão</Label>
                                <div className="grid grid-cols-2 gap-4">
                                    <div className="space-y-2">
                                        <Label className="text-sm text-muted-foreground flex items-center gap-1">
                                            <ThumbsDown className="w-3 h-3" /> Mínima
                                        </Label>
                                        <div className="space-y-2">
                                            <span className="text-lg font-semibold">{inputs.conversionRateMin}%</span>
                                            <Slider
                                                value={[inputs.conversionRateMin]}
                                                onValueChange={([value]) => updateInput('conversionRateMin', value)}
                                                max={100}
                                                min={1}
                                                step={1}
                                            />
                                        </div>
                                    </div>
                                    <div className="space-y-2">
                                        <Label className="text-sm text-muted-foreground flex items-center gap-1">
                                            <ThumbsUp className="w-3 h-3" /> Máxima
                                        </Label>
                                        <div className="space-y-2">
                                            <span className="text-lg font-semibold">{inputs.conversionRateMax}%</span>
                                            <Slider
                                                value={[inputs.conversionRateMax]}
                                                onValueChange={([value]) => updateInput('conversionRateMax', value)}
                                                max={100}
                                                min={1}
                                                step={1}
                                            />
                                        </div>
                                    </div>
                                </div>
                            </div>

                            <Separator />

                            <div className="space-y-2">
                                <Label className="flex items-center gap-2">
                                    <ShoppingCart className="w-4 h-4" />
                                    Ticket Médio
                                </Label>
                                <div className="relative">
                                    <span className="absolute left-3 top-1/2 transform -translate-y-1/2 text-muted-foreground">R$</span>
                                    <Input
                                        type="number"
                                        value={inputs.averageTicket}
                                        onChange={(e) => updateInput('averageTicket', Number(e.target.value))}
                                        className="pl-10"
                                    />
                                </div>
                            </div>
                        </CardContent>
                    </Card>
                </div>

                {/* Resultados */}
                <div className="space-y-6">
                    <Card>
                        <CardHeader>
                            <CardTitle className="flex items-center gap-2">
                                <Target className="w-5 h-5 text-green-600" />
                                Cenários de Resultado
                            </CardTitle>
                            <CardDescription>Projeções baseadas nas suas métricas</CardDescription>
                        </CardHeader>
                        <CardContent className="space-y-6">
                            {scenarios.map((scenario, index) => (
                                <div key={scenario.name}>
                                    <div className={`p-4 rounded-lg ${
                                        index === 0 ? 'bg-red-500/10 border border-red-500/20' :
                                            index === 1 ? 'bg-yellow-500/10 border border-yellow-500/20' :
                                                'bg-green-500/10 border border-green-500/20'
                                    }`}>
                                        <div className="flex items-center justify-between mb-3">
                                            <h4 className="font-semibold">{scenario.name}</h4>
                                            <Badge variant={index === 0 ? 'destructive' : index === 1 ? 'secondary' : 'default'}>
                                                {scenario.conversionRate}% conversão
                                            </Badge>
                                        </div>

                                        <div className="grid grid-cols-2 gap-4 text-sm">
                                            <div>
                                                <p className="text-muted-foreground">Vendas</p>
                                                <p className="text-lg font-semibold">{scenario.sales}</p>
                                            </div>
                                            <div>
                                                <p className="text-muted-foreground">Receita</p>
                                                <p className="text-lg font-semibold">{formatCurrency(scenario.revenue)}</p>
                                            </div>
                                            <div>
                                                <p className="text-muted-foreground">ROAS</p>
                                                <p className="text-lg font-semibold">{scenario.roas.toFixed(2)}x</p>
                                            </div>
                                            <div>
                                                <p className="text-muted-foreground">ROI</p>
                                                <p className={`text-lg font-semibold ${getROIColor(scenario.roi)}`}>
                                                    {scenario.roi.toFixed(1)}%
                                                </p>
                                            </div>
                                        </div>

                                        <Separator className="my-3" />

                                        <div className="flex justify-between items-center">
                                            <span className="text-sm text-muted-foreground">Lucro Líquido</span>
                                            <span className={`text-lg font-bold ${scenario.profit >= 0 ? 'text-green-500' : 'text-red-500'}`}>
                                                {formatCurrency(scenario.profit)}
                                            </span>
                                        </div>
                                    </div>
                                    {index < scenarios.length - 1 && <div className="h-4" />}
                                </div>
                            ))}
                        </CardContent>
                    </Card>

                    {/* Summary */}
                    <Card className="bg-gradient-to-br from-green-600 via-green-600 to-green-700 text-white">
                        <CardHeader>
                            <CardTitle className="text-white">Resumo da Análise</CardTitle>
                        </CardHeader>
                        <CardContent className="space-y-4">
                            <div className="flex justify-between">
                                <span className="text-white/80">Investimento Total</span>
                                <span className="font-semibold">{formatCurrency(inputs.totalInvestment)}</span>
                            </div>
                            <div className="flex justify-between">
                                <span className="text-white/80">Receita Mediana Esperada</span>
                                <span className="font-semibold">{formatCurrency(scenarios[1].revenue)}</span>
                            </div>
                            <Separator className="bg-white/20" />
                            <div className="flex justify-between text-lg">
                                <span className="font-medium">ROI Mediano</span>
                                <span className="font-bold">{scenarios[1].roi.toFixed(1)}%</span>
                            </div>
                        </CardContent>
                    </Card>
                </div>
            </div>
        </div>
    );
}
